mapper.select:
SELECT t.status AS status, t.label AS label, COUNT(*) AS count FROM ( SELECT CASE WHEN pat.legal_status = '授权' THEN 'VALID' WHEN pat.legal_status IN ('终止', '无效', '驳回') THEN 'INVALID' ELSE 'UNKNOWN' END AS status, CASE WHEN pat.legal_status = '授权' THEN '有效' WHEN pat.legal_status IN ('终止', '无效', '驳回') THEN '无效' ELSE '未知' END AS label, pat.dept_id FROM patent pat WHERE pat.status NOT IN ('DRAFT') ) t
AND t.dept_id = #{deptId}
GROUP BY t.status, t.label ORDER BY count DESC
